class Solution:
    def equalFrequency(self, word: str) -> bool:
        freq = {}
        for char in word:
            if char in freq:
                freq[char] += 1
            else:
                freq[char] = 1
        freq_values = list(freq.values())
        freq_values.sort()
        if len(freq_values) == 1:
            return True
        if len(freq_values) > 2:
            return False
        if freq_values[0] == freq_values[1] - 1 and freq_values[0] * len(freq_values) == len(word) - 1:
            return True
        if freq_values[0] + 1 == freq_values[1] and freq_values[0] * (len(freq_values) - 1) == len(word) - 1:
            return True
        return False
